Dynamic SQL fundamentals<pre><code>-- Simple dynamic query
SET @table_name = 'students';
SET @sql = CONCAT('SELECT COUNT(*) FROM ', @table_name);

PREPARE stmt FROM @sql;
EXECUTE stmt;
DEALLOCATE PREPARE stmt;
</code></pre> Dynamic ORDER BY — cannot use parameters for identifiers<pre><code>DELIMITER $$
CREATE PROCEDURE sp_get_students_sorted(
    IN  sort_column VARCHAR(30),
    IN  sort_dir    VARCHAR(4)      -- 'ASC' or 'DESC'
)
BEGIN
    -- Whitelist to prevent SQL injection
    IF sort_column NOT IN ('last_name','first_name','gpa','student_id') THEN
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = 'Invalid sort column';
    END IF;

    IF sort_dir NOT IN ('ASC','DESC') THEN
        SET sort_dir = 'ASC';
    END IF;

    SET @dyn_sql = CONCAT(
        'SELECT student_id, first_name, last_name, gpa ',
        'FROM students ORDER BY ', sort_column, ' ', sort_dir
    );

    PREPARE dyn_stmt FROM @dyn_sql;
    EXECUTE dyn_stmt;
    DEALLOCATE PREPARE dyn_stmt;
END$$
DELIMITER ;

CALL sp_get_students_sorted('gpa', 'DESC');
</code></pre> <p>SQL Injection Risk in Dynamic SQL</p> <p>Dynamic SQL with user-supplied values is a major injection vector. Always:</p> <ol> <li>Whitelist identifier values (column/table names) — never pass them as parameters directly</li> <li>Use parameterised placeholders (<code>?</code>) for data values in <code>EXECUTE stmt USING @var</code></li> <li>Validate and sanitise all inputs before building SQL strings</li> </ol> Using USING clause for safe data parameters<pre><code>-- Safe: user-supplied DATA goes through USING, not concatenation
SET @dept_id  = 3;
SET @min_gpa  = 3.0;
SET @dyn_sql  = 'SELECT * FROM students
                  WHERE dept_id = ? AND gpa &gt;= ?
                  ORDER BY last_name';

PREPARE dept_stmt FROM @dyn_sql;
EXECUTE dept_stmt USING @dept_id, @min_gpa;
DEALLOCATE PREPARE dept_stmt;
</code></pre>

Idempotent DDL patterns<pre><code>-- Table
CREATE TABLE IF NOT EXISTS schema_version (
    version_id  INT          NOT NULL,
    description VARCHAR(200) NOT NULL,
    applied_at  DATETIME     DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (version_id)
);

-- Column (no native IF NOT EXISTS in MySQL 8 for ADD COLUMN — use a procedure)
DROP PROCEDURE IF EXISTS add_column_if_not_exists;
DELIMITER $$
CREATE PROCEDURE add_column_if_not_exists(
    IN p_table  VARCHAR(64),
    IN p_column VARCHAR(64),
    IN p_def    VARCHAR(256)
)
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM information_schema.columns
        WHERE  table_schema = DATABASE()
          AND  table_name   = p_table
          AND  column_name  = p_column
    ) THEN
        SET @sql = CONCAT('ALTER TABLE `', p_table,
                          '` ADD COLUMN `', p_column, '` ', p_def);
        PREPARE s FROM @sql;
        EXECUTE s;
        DEALLOCATE PREPARE s;
    END IF;
END$$
DELIMITER ;

CALL add_column_if_not_exists('students', 'middle_name', 'VARCHAR(50) NULL AFTER first_name');
</code></pre>

